  1	import {
  2	  k8sCreate,
  3	  k8sPatch,
  4	  ResourceStatus,
  5	  useDeleteModal,
  6	} from '@openshift-console/dynamic-plugin-sdk';
  7	import * as React from 'react';
  8	import { PipelineRunModel } from '../../models';
  9	import { LoadingBox } from '../status/status-box';
 10	import DetailsPage from '../details-page/DetailsPage';
 11	import {
 12	  BreadcrumbItem,
 13	  Text,
 14	  TextVariants,
 15	  Tooltip,
 16	} from '@patternfly/react-core';
 17	import { Link } from 'react-router-dom-v5-compat';
 18	import { useTranslation } from 'react-i18next';
 19	import { navFactory } from '../utils/horizontal-nav';
 20	import PipelineRunDetails from './PipelineRunDetails';
 21	import ResourceYAMLEditorViewOnly from '../yaml-editor/ResourceYAMLEditorViewOnly';
 22	import {
 23	  chainsSignedAnnotation,
 24	  DELETED_RESOURCE_IN_K8S_ANNOTATION,
 25	  RESOURCE_LOADED_FROM_RESULTS_ANNOTATION,
 26	  PIPELINE_RUN_MANAGED_BY_KUEUE_LABEL,
 27	} from '../../consts';
 28	import { ArchiveIcon, MulticlusterIcon } from '@patternfly/react-icons';
 29	import SignedBadgeIcon from '../../images/SignedBadge';
 30	import Status from '../status/Status';
 31	import { ComputedStatus } from '../../types';
 32	import {
 33	  pipelineRunFilterReducer,
 34	  pipelineRunTitleFilterReducer,
 35	} from '../utils/pipeline-filter-reducer';
 36	import PipelineRunParametersForm from './PipelineRunParametersForm';
 37	import { PipelineRunLogsWithActiveTask } from './PipelineRunLogs';
 38	import PipelineRunEvents from './PipelineRunEvents';
 39	import { returnValidPipelineRunModel } from '../utils/pipeline-utils';
 40	import { getPipelineRunData, resourcePathFromModel } from '../utils/utils';
 41	import { errorModal } from '../modals/error-modal';
 42	import {
 43	  isResourceLoadedFromTR,
 44	  tektonResultsFlag,
 45	} from '../utils/common-utils';
 46	import { useNavigate } from 'react-router-dom-v5-compat';
 47	import {
 48	  shouldHidePipelineRunCancel,
 49	  shouldHidePipelineRunStop,
 50	} from '../utils/pipeline-augment';
 51	import {
 52	  getTaskRunsOfPipelineRun,
 53	  usePipelineRun,
 54	  useTaskRuns,
 55	} from '../hooks/useTaskRuns';
 56	import { useGetActiveUser } from '../hooks/hooks';
 57	
 58	type PipelineRunDetailsPageProps = {
 59	  name: string;
 60	  namespace: string;
 61	};
 62	
 63	const PipelineRunDetailsPage: React.FC<PipelineRunDetailsPageProps> = ({
 64	  name,
 65	  namespace,
 66	}) => {
 67	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 68	  const navigate = useNavigate();
 69	  const [pipelineRun, pipelineRunLoaded] = usePipelineRun(namespace, name);
 70	  const plrStatus = pipelineRunFilterReducer(pipelineRun);
 71	  const pipelineRunFinished =
 72	    plrStatus !== ComputedStatus.Running &&
 73	    plrStatus !== ComputedStatus.Pending &&
 74	    plrStatus !== ComputedStatus.Cancelling;
 75	  const [taskRuns] = useTaskRuns(namespace, name, {
 76	    pipelineRunFinished,
 77	    pipelineRunManagedBy: pipelineRun?.spec?.managedBy,
 78	  });
 79	  const PLRTasks = getTaskRunsOfPipelineRun(taskRuns, name);
 80	  const currentUser = useGetActiveUser();
 81	
 82	  const reRunAction = () => {
 83	    const { pipelineRef, pipelineSpec } = pipelineRun.spec;
 84	    if (
 85	      namespace &&
 86	      (pipelineRef?.name || pipelineSpec || pipelineRef?.resolver)
 87	    ) {
 88	      k8sCreate({
 89	        model: returnValidPipelineRunModel(pipelineRun),
 90	        data: getPipelineRunData(null, currentUser, pipelineRun),
 91	      }).then((plr) => {
 92	        navigate(
 93	          resourcePathFromModel(
 94	            PipelineRunModel,
 95	            plr.metadata.name,
 96	            plr.metadata.namespace,
 97	          ),
 98	        );
 99	      });
100	    } else {
101	      errorModal({
102	        error: t(
103	          'Invalid PipelineRun configuration, unable to start Pipeline.',
104	        ),
105	      });
106	    }
107	  };
108	
109	  const cancelAction = () => {
110	    k8sPatch({
111	      model: PipelineRunModel,
112	      resource: {
113	        metadata: {
114	          name,
115	          namespace,
116	        },
117	      },
118	      data: [
119	        {
120	          op: 'replace',
121	          path: `/spec/status`,
122	          value: 'CancelledRunFinally',
123	        },
124	      ],
125	    });
126	  };
127	
128	  const stopAction = () => {
129	    k8sPatch({
130	      model: PipelineRunModel,
131	      resource: {
132	        metadata: { name, namespace },
133	      },
134	      data: [
135	        {
136	          op: 'replace',
137	          path: `/spec/status`,
138	          value: 'StoppedRunFinally',
139	        },
140	      ],
141	    });
142	  };
143	
144	  const message = (
145	    <p>
146	      {t(
147	        'This action will delete resource from k8s but still the resource can be fetched from Tekton Results',
148	      )}
149	    </p>
150	  );
151	
152	  const launchDeleteModal =
153	    !isResourceLoadedFromTR(pipelineRun) && tektonResultsFlag(pipelineRun)
154	      ? useDeleteModal(pipelineRun, undefined, message)
155	      : useDeleteModal(pipelineRun);
156	
157	  const resourceTitleFunc = React.useMemo((): string | JSX.Element => {
158	    return (
159	      <div className="pipelinerun-details-page pf-v6-l-flex pf-v5-l-gap-md pf-v6-u-align-items-center">
160	        {pipelineRun?.metadata?.name}{' '}
161	        {pipelineRun?.metadata?.annotations?.[chainsSignedAnnotation] ===
162	          'true' && (
163	          <Tooltip content={t('Signed')}>
164	            <div className="opp-pipeline-run-details__signed-indicator">
165	              <SignedBadgeIcon width="18" height="18" />
166	            </div>
167	          </Tooltip>
168	        )}
169	        {(pipelineRun?.metadata?.annotations?.[
170	          DELETED_RESOURCE_IN_K8S_ANNOTATION
171	        ] === 'true' ||
172	          pipelineRun?.metadata?.annotations?.[
173	            RESOURCE_LOADED_FROM_RESULTS_ANNOTATION
174	          ] === 'true') && (
175	          <Tooltip content={t('Archived in Tekton results')}>
176	            <ArchiveIcon className="pipelinerun-details-page__results-indicator" />
177	          </Tooltip>
178	        )}
179	        {pipelineRun?.spec?.managedBy ===
180	          PIPELINE_RUN_MANAGED_BY_KUEUE_LABEL && (
181	          <Tooltip content={t('Multicluster Pipeline Run')}>
182	            <MulticlusterIcon className="pipelinerun-details-page__results-indicator" />
183	          </Tooltip>
184	        )}
185	        <ResourceStatus>
186	          <Status
187	            status={pipelineRunFilterReducer(pipelineRun)}
188	            title={pipelineRunTitleFilterReducer(pipelineRun)}
189	          />
190	        </ResourceStatus>
191	      </div>
192	    );
193	  }, [pipelineRun]);
194	  if (!pipelineRunLoaded) {
195	    return <LoadingBox />;
196	  }
197	  return (
198	    <DetailsPage
199	      obj={pipelineRun}
200	      headTitle={name}
201	      title={<Text component={TextVariants.h1}>{resourceTitleFunc}</Text>}
202	      model={PipelineRunModel}
203	      breadcrumbs={[
204	        <BreadcrumbItem key="app-link" component="div">
205	          <Link
206	            data-test="breadcrumb-link"
207	            className="pf-v6-c-breadcrumb__link"
208	            to={`/pipelines/ns/${namespace}/pipeline-runs`}
209	          >
210	            {t('PipelineRuns')}
211	          </Link>
212	        </BreadcrumbItem>,
213	        {
214	          path: `/pipelines/ns/${namespace}/`,
215	          name: t('PipelineRun details'),
216	        },
217	      ]}
218	      pages={[
219	        navFactory.details(PipelineRunDetails),
220	        navFactory.editYaml(ResourceYAMLEditorViewOnly),
221	        {
222	          href: 'parameters',
223	          name: t('Parameters'),
224	          component: (pageProps) => (
225	            <PipelineRunParametersForm obj={pipelineRun} {...pageProps} />
226	          ),
227	        },
228	        {
229	          href: 'logs',
230	          name: t('Logs'),
231	          component: PipelineRunLogsWithActiveTask,
232	        },
233	        navFactory.events(PipelineRunEvents),
234	      ]}
235	      actions={[
236	        {
237	          key: 'rerun-pipelineRun',
238	          label: t('Rerun'),
239	          onClick: () => reRunAction(),
240	        },
241	        {
242	          key: 'stop-pipelineRun',
243	          label: t('Stop'),
244	          tooltipProps: {
245	            content: t(
246	              'Let the running tasks complete, then execute finally tasks',
247	            ),
248	          },
249	          onClick: () => stopAction(),
250	          hidden: shouldHidePipelineRunStop(pipelineRun, PLRTasks),
251	        },
252	        {
253	          key: 'cancel-pipelineRun',
254	          label: t('Cancel'),
255	          tooltipProps: {
256	            content: t(
257	              'Interrupt any executing non finally tasks, then execute finally tasks',
258	            ),
259	          },
260	          onClick: () => cancelAction(),
261	          hidden: shouldHidePipelineRunCancel(pipelineRun, PLRTasks),
262	        },
263	        {
264	          key: 'delete-pipelineRun',
265	          label: t('Delete PipelineRun'),
266	          onClick: () => launchDeleteModal(),
267	          isDisabled: isResourceLoadedFromTR(pipelineRun),
268	        },
269	      ]}
270	    />
271	  );
272	};
273	
274	export default PipelineRunDetailsPage;

